const ctx = $('CONTEXT').item.json;
const params = $('Parse RSVP Output').item.json.output.parameters;

const proyectoNombre = ctx.proyecto_nombre || ctx.proyecto;
const intencion = params.intencion_compra === 'V' ? 'Vivir' : params.intencion_compra === 'I' ? 'Invertir' : '-';
const contacto = {'2':'Correo','3':'Llamada','4':'WhatsApp','5':'Cualquiera'}[params.metodo_contacto_pref] || '-';

const esCita = ['cita_presencial', 'cita_virtual'].includes(params.tipo_agendamiento);

const tipoLabel = {
  'cita_presencial': '🏢 Visita presencial en sala de ventas',
  'cita_virtual': '💻 Cita virtual (Teams / Meet / Zoom)',
  'llamada': '📞 Llamada telefónica'
}[params.tipo_agendamiento] || '-';

const fechaIso = params.fecha_hora || $('Find Appointment').first().json.fecha_hora;
let fecha = '-';
if (fechaIso) {
    const hasOffset = /[+-]\d{2}:?\d{2}$|Z$/.test(fechaIso);
  const dt = hasOffset
    ? DateTime.fromISO(fechaIso).setZone('America/Guatemala')
    : DateTime.fromISO(fechaIso, { zone: 'America/Guatemala' });
  if (dt.isValid) {
    const txt = dt.setLocale('es').toFormat("cccc d 'de' LLLL 'de' yyyy 'a las' h:mm a");
    fecha = txt.charAt(0).toUpperCase() + txt.slice(1) + ' (hora Guatemala)';
  }
}
const medioLlamadaLabel = params.medio_llamada === 'whatsapp' ? '📱 WhatsApp' : params.medio_llamada === 'telefono' ? '📞 Teléfono' : '-';

const html = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="utf-8"><title>Nueva cita — SPECTRUM VIVIENDA</title></head>
<body style="background:#f7f7f8;margin:0;padding:0;font-family:Arial,sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0">
<tr><td align="center" style="padding:28px 16px;">
<table width="600" cellpadding="0" cellspacing="0" style="background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);">

  <tr><td style="background:#1a1a2e;padding:24px 32px;">
    <h1 style="color:#fff;margin:0;font-size:20px;">🏢 SPECTRUM VIVIENDA</h1>
    <p style="color:#a0a0b0;margin:4px 0 0;font-size:14px;">
      ${esCita ? 'Nueva cita registrada' : 'Nueva solicitud de llamada'}
    </p>
  </td></tr>

  <tr><td style="background:#f0f4ff;padding:16px 32px;border-bottom:1px solid #e0e8ff;">
    <p style="margin:0;font-size:16px;font-weight:bold;color:#1a1a2e;">📍 ${proyectoNombre}</p>
    <p style="margin:4px 0 0;font-size:14px;color:#555;">${tipoLabel}</p>
  </td></tr>

  <tr><td style="padding:24px 32px;">
    <h2 style="font-size:13px;text-transform:uppercase;color:#888;margin:0 0 12px;">Datos del Lead</h2>
    <table width="100%" cellpadding="0" cellspacing="0">
      <tr><td style="padding:5px 0;font-size:14px;color:#555;width:45%;">Nombre</td>
          <td style="font-size:14px;color:#1a1a2e;font-weight:bold;">${ctx.nombre}</td></tr>
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Correo</td>
          <td style="font-size:14px;color:#1a1a2e;">${ctx.correo}</td></tr>
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Teléfono</td>
          <td style="font-size:14px;color:#1a1a2e;">${ctx.telefono}</td></tr>
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Intención</td>
          <td style="font-size:14px;color:#1a1a2e;">${intencion}</td></tr>
      ${params.estado_civil ? `
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Estado civil</td>
          <td style="font-size:14px;color:#1a1a2e;">${params.estado_civil}</td></tr>` : ''}
    </table>
  </td></tr>

  <tr><td style="padding:0 32px 24px;">
    <h2 style="font-size:13px;text-transform:uppercase;color:#888;margin:0 0 12px;">
      ${esCita ? 'Detalles de la cita' : 'Detalles de la llamada'}
    </h2>
    <table width="100%" cellpadding="0" cellspacing="0">
      <tr><td style="padding:5px 0;font-size:14px;color:#555;width:45%;">Tipo</td>
          <td style="font-size:14px;color:#1a1a2e;font-weight:bold;">${tipoLabel}</td></tr>
      ${esCita ? `
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Fecha y hora</td>
          <td style="font-size:14px;color:#1a1a2e;font-weight:bold;">${fecha}</td></tr>
      ${params.numero_habitaciones ? `
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Habitaciones</td>
          <td style="font-size:14px;color:#1a1a2e;">${params.numero_habitaciones}</td></tr>` : ''}
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Contacto preferido</td>
          <td style="font-size:14px;color:#1a1a2e;">${contacto}</td></tr>` : `
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Horario preferido</td>
          <td style="font-size:14px;color:#1a1a2e;font-weight:bold;">${params.horario_preferido || '-'}</td></tr>
      <tr><td style="padding:5px 0;font-size:14px;color:#555;">Medio de llamada</td>
          <td style="font-size:14px;color:#1a1a2e;font-weight:bold;">${medioLlamadaLabel}</td></tr>`}
    </table>
  </td></tr>

  <tr><td style="background:#f7f7f8;padding:14px 32px;border-top:1px solid #eee;">
    <p style="margin:0;font-size:12px;color:#aaa;text-align:center;">
      Sistema automatizado SPECTRUM VIVIENDA · ${new Date().toLocaleString('es-GT', {timeZone:'America/Guatemala'})}
    </p>
  </td></tr>

</table>
</td></tr>
</table>
</body>
</html>`;

return [{ json: { html, fecha, modalidad: tipoLabel, tipo_agendamiento: params.tipo_agendamiento || null, horario_preferido: params.horario_preferido || null, medio_llamada: params.medio_llamada || null, medio_llamada_label: medioLlamadaLabel } }];

const raw = $input.first().json.output || '';

function extractJSON(text) {
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) return null;
  try {
    return JSON.parse(match[0]);
  } catch(e) {
    return null;
  }
}

const parsed = extractJSON(raw);

if (!parsed) {
  return [{
    json: {
      output: {
        response: raw,
        parameters: {
          tipo_agendamiento: null,
          horario_preferido: null,
          medio_llamada: null,
          fecha_hora: null,
          numero_habitaciones: null,
          intencion_compra: null,
          metodo_contacto_pref: null,
          estado_civil: null,
          cita_confirmada: false
        }
      }
    }
  }];
}

const p = parsed.parameters || {};

// Normaliza valores "null" string a null real
const norm = (v) => (v === 'null' || v === '' || v === undefined) ? null : v;

return [{
  json: {
    output: {
      response: parsed.response || raw,
      parameters: {
        tipo_agendamiento: norm(p.tipo_agendamiento),
        horario_preferido: norm(p.horario_preferido),
        medio_llamada: (() => { const v = norm(p.medio_llamada); if (!v) return null; const s = String(v).toLowerCase().replace(/[^a-z]/g, ''); if (s.includes('whats')) return 'whatsapp'; if (s.includes('telef') || s.includes('phone') || s === 'tel') return 'telefono'; return s === 'telefono' || s === 'whatsapp' ? s : null; })(),
        fecha_hora: (() => { const raw = norm(p.fecha_hora); if (!raw) return null; const local =
  raw.replace(/(\.[0-9]+)?(Z|[+-]\d{2}:?\d{2})$/, ''); return local + '-06:00'; })(),
        numero_habitaciones: norm(p.numero_habitaciones),
        intencion_compra: norm(p.intencion_compra),
        metodo_contacto_pref: norm(p.metodo_contacto_pref),
        estado_civil: norm(p.estado_civil),
        cita_confirmada: p.cita_confirmada === true
      }
    }
  }
}];
